# Inspect the construction planes for the lip features (Plane7 and Plane8)
# and the extrude features for the lips (Extrude8 and Extrude9)
# to understand the clearance between lip and back wall

timeline = design.timeline
results = {}

for i in [3, 6, 7, 8, 9, 26, 27, 28, 29, 30, 31]:
    entry = timeline.item(i)
    entity = entry.entity
    entity_type = entity.objectType
    info = {'index': i, 'name': entry.name, 'type': entity_type}

    if 'ConstructionPlane' in entity_type:
        try:
            plane = entity.geometry
            info['plane_origin'] = [plane.origin.x, plane.origin.y, plane.origin.z]
            info['plane_normal'] = [plane.normal.x, plane.normal.y, plane.normal.z]
        except:
            info['plane_note'] = 'Could not get plane geometry'

    if 'ExtrudeFeature' in entity_type:
        try:
            info['extrude_bodies'] = entity.bodies.count
            if entity.bodies.count > 0:
                body = entity.bodies.item(0)
                bb = body.boundingBox
                info['body_bb'] = {
                    'min': [bb.minPoint.x, bb.minPoint.y, bb.minPoint.z],
                    'max': [bb.maxPoint.x, bb.maxPoint.y, bb.maxPoint.z]
                }
        except:
            pass
        try:
            ext_def = entity.extentOne
            info['extent_type'] = str(type(ext_def))
            if hasattr(ext_def, 'distance'):
                info['distance'] = ext_def.distance.value
        except:
            pass

    results[i] = info

result = results

# Force model regeneration by rolling the timeline to the end
# and triggering a compute
try:
    # Move timeline marker to end to force full recompute
    tl = design.timeline
    tl.moveToEnd()
    result = {'status': 'timeline moved to end, recompute triggered'}
except Exception as e:
    result = {'error': str(e)}
